#include <stdio.h>
#include <string.h>
#include <stdbool.h>

int countInterestingSubstrings(char *s, int k) {
    int n = strlen(s);
    int count = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j <= n; j++) {
            int freq[26] = {0};
            int distinct = 0;
            for (int l = i; l < j; l++) {
                int idx = s[l] - 'a';
                if (freq[idx] == 0) distinct++;
                freq[idx]++;
            }
            bool interesting = true;
            if (distinct < k) interesting = false;
            else {
                int f = freq[s[i] - 'a'];
                for (int l = 0; l < 26; l++) {
                    if (freq[l] > 0 && freq[l] != f) {
                        interesting = false;
                        break;
                    }
                }
            }
            if (interesting) count++;
        }
    }
    return count;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        char s[7001];
        int k;
        scanf("%s %d", s, &k);
        printf("%d\n", countInterestingSubstrings(s, k));
    }
    return 0;
}

