#include <iostream>
#include <string>
#include <unordered_map>

int countInterestingSubstrings(const std::string &s, int k) {
    int n = s.size();
    int count = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j <= n; j++) {
            std::unordered_map<char, int> freq;
            int distinct = 0;
            for (int l = i; l < j; l++) {
                if (freq.find(s[l]) == freq.end()) distinct++;
                freq[s[l]]++;
            }
            bool interesting = true;
            if (distinct < k) interesting = false;
            else {
                int f = freq[s[i]];
                for (const auto &p : freq) {
                    if (p.second != f) {
                        interesting = false;
                        break;
                    }
                }
            }
            if (interesting) count++;
        }
    }
    return count;
}

