        for j in range(i + 1, n + 1):
            freq = {}
            distinct = 0
            for l in range(i, j):
                if s[l] not in freq:
                    distinct += 1
                freq[s[l]] = freq.get(s[l], 0) + 1
            interesting = True
            if distinct < k:
                interesting = False
            else:
                f = freq[s[i]]
                for l in freq.values():
                    if l != f:
                        interesting = False
                        break
            if interesting:
                count += 1
    return count

